## 2. Component Testing with React Testing Library

While Jest tests your logic, **React Testing Library (RTL)** helps you test what the user actually sees and interacts with. It encourages testing behavior over implementation.

RTL provides utilities to:

- Render components in a virtual DOM (`render`)
- Query the DOM (`getBy`, `findBy`, `queryBy`)
- Simulate user events (`fireEvent`, `userEvent`)
- Assert on rendered output

### Example: Testing a Login Form

```jsx
// src/components/LoginForm.jsx
import { useState } from 'react';

export default function LoginForm({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!email || !password) {
      setError('Email and password are required');
      return;
    }
    onLogin({ email, password });
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        type="email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        data-testid="email-input"
        placeholder="Email"
      />
      <input
        type="password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        data-testid="password-input"
        placeholder="Password"
      />
      {error && <p data-testid="error-message">{error}</p>}
      <button type="submit" data-testid="submit-button">
        Login
      </button>
    </form>
  );
}
```

Now, write a test:

```jsx
// src/components/LoginForm.test.jsx
import { render, screen, fireEvent } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import LoginForm from './LoginForm';

describe('LoginForm', () => {
  it('renders email and password inputs', () => {
    render(<LoginForm onLogin={() => {}} />);
    expect(screen.getByPlaceholderText('Email')).toBeInTheDocument();
    expect(screen.getByPlaceholderText('Password')).toBeInTheDocument();
  });

  it('shows error when form is submitted without inputs', async () => {
    const mockLogin = jest.fn();
    render(<LoginForm onLogin={mockLogin} />);

    fireEvent.click(screen.getByTestId('submit-button'));
    expect(await screen.findByTestId('error-message')).toHaveTextContent(
      'Email and password are required'
    );
    expect(mockLogin).not.toHaveBeenCalled();
  });

  it('calls onLogin with correct credentials', async () => {
    const user = userEvent.setup();
    const mockLogin = jest.fn();
    render(<LoginForm onLogin={mockLogin} />);

    await user.type(screen.getByTestId('email-input'), 'user@example.com');
    await user.type(screen.getByTestId('password-input'), 'password123');
    await user.click(screen.getByTestId('submit-button'));

    expect(mockLogin).toHaveBeenCalledWith({
      email: 'user@example.com',
      password: 'password123',
    });
  });
});
```

> 🔍 **Key Insight:** Use `data-testid` for stable selectors. Avoid querying by CSS classes or text that may change.

